import { page } from 'vitest/browser';
import { beforeEach, describe, expect, it } from 'vitest';
import { render } from 'vitest-browser-svelte';
import Selector from './Selector.svelte';
import { appState } from './state.svelte.js';

describe('Selector', () => {
	beforeEach(() => {
		appState.currentlySelected = 0;
	});

	it('renders all chat names', async () => {
		render(Selector);
		for (const chat of appState.chats) {
			await expect.element(page.getByText(chat.name)).toBeInTheDocument();
		}
	});

	it('each row has a status-dot element', async () => {
		render(Selector);
		const dots = page.locator('.status-dot');
		await expect.element(dots.first()).toBeInTheDocument();
		expect(await dots.count()).toBe(appState.chats.length);
	});

	it('first chat row has class selected by default', async () => {
		render(Selector);
		const rows = page.locator('.chat-row');
		await expect.element(rows.first()).toHaveClass('selected');
	});

	it('clicking a chat sets appState.currentlySelected', async () => {
		render(Selector);
		await page.locator('.chat-row').nth(2).click();
		expect(appState.currentlySelected).toBe(2);
	});

	it('selected class moves to the clicked row', async () => {
		render(Selector);
		await page.locator('.chat-row').nth(1).click();
		const rows = page.locator('.chat-row');
		await expect.element(rows.nth(0)).not.toHaveClass('selected');
		await expect.element(rows.nth(1)).toHaveClass('selected');
	});

	it('last message preview text appears for chats with messages', async () => {
		render(Selector);
		// Jordan (index 1) has a message
		const jordan = appState.chats[1];
		const lastMsg = jordan.messages.at(-1)!;
		await expect.element(page.getByText(lastMsg.text)).toBeInTheDocument();
	});

	it('.chat-preview.empty appears for chats without messages', async () => {
		render(Selector);
		// Claudia (index 0) has no messages
		await expect.element(page.locator('.chat-preview.empty')).toBeInTheDocument();
	});
});

